          case 'sharpe':
            aValue = a.metrics.sharpe;
            bValue = b.metrics.sharpe;
            break;
          case 'followers':
            aValue = a.followerCount;
            bValue = b.followerCount;
            break;
          case 'maxDrawdown':
            aValue = a.maxDrawdownPercent;
            bValue = b.maxDrawdownPercent;
            break;
          case 'winRate':
            aValue = a.winRatePercent;
            bValue = b.winRatePercent;
